    56→  class StrictHeaderChecker {
    57→  public:
    58→    struct HeaderCheckResult {
    59→      bool valid_ = true;
    60→      const Http::HeaderEntry* entry_;
    61→    };
    62→
    63→    /**
    64→     * Determine whether a given header's value passes the strict validation
    65→     * defined for that header.
    66→     * @param headers supplies the headers from which to get the target header.
    67→     * @param target_header is the header to be validated.
    68→     * @return HeaderCheckResult containing the entry for @param target_header
    69→     *         and valid_ set to FALSE if @param target_header is set to an
    70→     *         invalid value. If @param target_header doesn't appear in
    71→     *         @param headers, return a result with valid_ set to TRUE.
    72→     */
    73→    static const HeaderCheckResult checkHeader(Http::RequestHeaderMap& headers,
    74→                                               const Http::LowerCaseString& target_header);
    75→
    76→    using ParseRetryFlagsFunc = std::function<std::pair<uint32_t, bool>(absl::string_view)>;
    77→
    78→  private:
    79→    static HeaderCheckResult hasValidRetryFields(const Http::HeaderEntry* header_entry,
    80→                                                 const ParseRetryFlagsFunc& parse_fn) {
    81→      HeaderCheckResult r;
    82→      if (header_entry) {
    83→        const auto flags_and_validity = parse_fn(header_entry->value().getStringView());
    84→        r.valid_ = flags_and_validity.second;
    85→        r.entry_ = header_entry;
    86→      }
    87→      return r;
    88→    }
    89→
    90→    static HeaderCheckResult isInteger(const Http::HeaderEntry* header_entry) {
    91→      HeaderCheckResult r;
    92→      if (header_entry) {
    93→        uint64_t out;
    94→        r.valid_ = absl::SimpleAtoi(header_entry->value().getStringView(), &out);
    95→        r.entry_ = header_entry;
    96→      }
    97→      return r;
    98→    }
    99→  };
