   204→      : factory_context_(factory_context), router_context_(router_context), scope_(scope), cm_(cm),
   205→        runtime_(runtime), default_stats_(router_context_.statNames(), scope_, stat_prefix),
   206→        async_stats_(router_context_.statNames(), scope, http_context.asyncClientStatPrefix()),
   207→        random_(random), emit_dynamic_stats_(emit_dynamic_stats),
   208→        start_child_span_(start_child_span), suppress_envoy_headers_(suppress_envoy_headers),
   209→        respect_expected_rq_timeout_(respect_expected_rq_timeout),
   210→        suppress_grpc_request_failure_code_stats_(suppress_grpc_request_failure_code_stats),
   211→        flush_upstream_log_on_upstream_stream_(flush_upstream_log_on_upstream_stream),
   212→        http_context_(http_context), zone_name_(factory_context.localInfo().zoneStatName()),
   213→        shadow_writer_(std::move(shadow_writer)), time_source_(time_source) {
   214→    if (!strict_check_headers.empty()) {
   215→      strict_check_headers_ = std::make_unique<HeaderVector>();
   216→      for (const auto& header : strict_check_headers) {
