   315→  void onDestroy() override;
   316→
   317→  Http::LocalErrorStatus onLocalReply(const LocalReplyData&) override {
   318→    // If there's a local reply (e.g. timeout) during host selection, cancel host
   319→    // selection.
   320→    if (host_selection_cancelable_) {
   321→      host_selection_cancelable_->cancel();
   322→      host_selection_cancelable_.reset();
   323→    }
   324→
   325→    // Clean up the upstream_requests_.
   326→    if (Runtime::runtimeFeatureEnabled(
   327→            "envoy.reloadable_features.router_filter_resetall_on_local_reply")) {
