   347→  absl::optional<uint64_t> computeHashKey() override {
   348→    if (route_entry_ && downstream_headers_) {
   349→      auto hash_policy = route_entry_->hashPolicy();
   350→      if (hash_policy) {
   351→        return hash_policy->generateHash(
   352→            *downstream_headers_, callbacks_->streamInfo(),
   353→            [this](absl::string_view key, absl::string_view path, std::chrono::seconds max_age,
   354→                   absl::Span<const Http::CookieAttribute> attributes) -> std::string {
   355→              return addDownstreamSetCookie(key, path, max_age, attributes);
   356→            });
   357→      }
   358→    }
   359→    return {};
   360→  }
   361→  const Router::MetadataMatchCriteria* metadataMatchCriteria() override {
   362→    if (route_entry_) {
   363→      // Have we been called before? If so, there's no need to recompute because
   364→      // by the time this method is called for the first time, route_entry_ should
   365→      // not change anymore.
   366→      if (metadata_match_ != nullptr) {
   367→        return metadata_match_.get();
   368→      }
   369→
   370→      // The request's metadata, if present, takes precedence over the route's.
   371→      const auto& request_metadata = callbacks_->streamInfo().dynamicMetadata().filter_metadata();
   372→      const auto filter_it = request_metadata.find(Envoy::Config::MetadataFilters::get().ENVOY_LB);
   373→      if (filter_it != request_metadata.end()) {
   374→        if (route_entry_->metadataMatchCriteria() != nullptr) {
   375→          metadata_match_ =
   376→              route_entry_->metadataMatchCriteria()->mergeMatchCriteria(filter_it->second);
   377→        } else {
   378→          metadata_match_ = std::make_unique<Router::MetadataMatchCriteriaImpl>(filter_it->second);
   379→        }
   380→        return metadata_match_.get();
   381→      }
   382→      return route_entry_->metadataMatchCriteria();
   383→    }
