   443→  /**
   444→   * Set a computed cookie to be sent with the downstream headers.
   445→   * @param key supplies the size of the cookie
   446→   * @param max_age the lifetime of the cookie
   447→   * @param  path the path of the cookie, or ""
   448→   * @return std::string the value of the new cookie
   449→   */
   450→  std::string addDownstreamSetCookie(absl::string_view key, absl::string_view path,
   451→                                     std::chrono::seconds max_age,
   452→                                     absl::Span<const Http::CookieAttribute> attributes) {
   453→    // The cookie value should be the same per connection so that if multiple
   454→    // streams race on the same path, they all receive the same cookie.
   455→    // Since the downstream port is part of the hashed value, multiple HTTP1
   456→    // connections can receive different cookies if they race on requests.
   457→    std::string value;
   458→    const Network::Connection* conn = downstreamConnection();
   459→    // Need to check for null conn if this is ever used by Http::AsyncClient in the future.
   460→    value = conn->connectionInfoProvider().remoteAddress()->asString() +
   461→            conn->connectionInfoProvider().localAddress()->asString();
   462→
   463→    const std::string cookie_value = Hex::uint64ToHex(HashUtil::xxHash64(value));
   464→    downstream_set_cookies_.emplace_back(
   465→        Http::Utility::makeSetCookieValue(key, cookie_value, path, max_age, true, attributes));
   466→    return cookie_value;
   467→  }
