   995→    state_.encoder_filter_chain_aborted_ = true;
   996→  }
   997→  // When independent half-close is enabled local reply always stops decoder filter chain.
   998→  if (filter_manager_callbacks_.isHalfCloseEnabled()) {
   999→    state_.decoder_filter_chain_aborted_ = true;
  1000→  }
  1001→
  1002→  streamInfo().setResponseCodeDetails(details);
  1003→  StreamFilterBase::LocalReplyData data{code, grpc_status, details, false};
  1004→  onLocalReply(data);
  1005→  if (data.reset_imminent_) {
  1006→    ENVOY_STREAM_LOG(debug, "Resetting stream due to {}. onLocalReply requested reset.", *this,
  1007→                     details);
  1008→    filter_manager_callbacks_.resetStream(Http::StreamResetReason::LocalReset, "");
  1009→    return;
  1010→  }
  1011→
  1012→  if (!filter_manager_callbacks_.responseHeaders().has_value() &&
