    25→absl::StatusOr<Formatter::FormatterPtr>
    26→parseHttpHeaderFormatter(const envoy::config::core::v3::HeaderValue& header_value) {
    27→  const std::string& key = header_value.key();
    28→  // PGV constraints provide this guarantee.
    29→  ASSERT(!key.empty());
    30→  // We reject :path/:authority rewriting, there is already a well defined mechanism to
    31→  // perform this in the RouteAction, and doing this via request_headers_to_add
    32→  // will cause us to have to worry about interaction with other aspects of the
    33→  // RouteAction, e.g. prefix rewriting. We also reject other :-prefixed
    34→  // headers, since it seems dangerous and there doesn't appear a use case.
    35→  // Host is disallowed as it created confusing and inconsistent behaviors for
    36→  // HTTP/1 and HTTP/2. It could arguably be allowed on the response path.
    37→  if (!Http::HeaderUtility::isModifiableHeader(key)) {
    38→    return absl::InvalidArgumentError(":-prefixed or host headers may not be modified");
    39→  }
    40→
    41→  // UPSTREAM_METADATA and DYNAMIC_METADATA must be translated from JSON ["a", "b"] format to colon
    42→  // format (a:b)
    43→  std::string final_header_value = HeaderParser::translateMetadataFormat(header_value.value());
    44→  // Change PER_REQUEST_STATE to FILTER_STATE.
    45→  final_header_value = HeaderParser::translatePerRequestState(final_header_value);
    46→
    47→  // Let the substitution formatter parse the final_header_value.
    48→  return Envoy::Formatter::FormatterImpl::create(final_header_value, true);
    49→}
    50→
    51→} // namespace
    52→
    53→HeadersToAddEntry::HeadersToAddEntry(const HeaderValueOption& header_value_option,
    54→                                     absl::Status& creation_status)
    55→    : original_value_(header_value_option.header().value()),
    56→      add_if_empty_(header_value_option.keep_empty_value()) {
    57→
    58→  if (header_value_option.has_append()) {
    59→    // 'append' is set and ensure the 'append_action' value is equal to the default value.
    60→    if (header_value_option.append_action() != HeaderValueOption::APPEND_IF_EXISTS_OR_ADD) {
    61→      creation_status =
    62→          absl::InvalidArgumentError("Both append and append_action are set and it's not allowed");
    63→      return;
    64→    }
    65→
    66→    append_action_ = header_value_option.append().value()
    67→                         ? HeaderValueOption::APPEND_IF_EXISTS_OR_ADD
    68→                         : HeaderValueOption::OVERWRITE_IF_EXISTS_OR_ADD;
    69→  } else {
    70→    append_action_ = header_value_option.append_action();
    71→  }
    72→
    73→  auto formatter_or_error = parseHttpHeaderFormatter(header_value_option.header());
    74→  SET_AND_RETURN_IF_NOT_OK(formatter_or_error.status(), creation_status);
    75→  formatter_ = std::move(formatter_or_error.value());
    76→}
