   104→    HeaderAppendAction append_action) {
   105→  HeaderParserPtr header_parser(new HeaderParser());
   106→
   107→  header_parser->headers_to_add_.reserve(headers_to_add.size());
   108→  for (const auto& header_value : headers_to_add) {
   109→    auto entry_or_error = HeadersToAddEntry::create(header_value, append_action);
   110→    RETURN_IF_NOT_OK_REF(entry_or_error.status());
   111→    header_parser->headers_to_add_.emplace_back(Http::LowerCaseString(header_value.key()),
   112→                                                std::move(entry_or_error.value()));
   113→  }
   114→
   115→  return header_parser;
