    59→      HeaderMutations::create(config.request_trailers_mutations());
    60→  SET_AND_RETURN_IF_NOT_OK(request_trailers_mutations_or_error.status(), creation_status);
    61→  request_trailers_mutations_ = std::move(request_trailers_mutations_or_error.value());
