   169→Http::FilterHeadersStatus HeaderMutation::decodeHeaders(Http::RequestHeaderMap& headers, bool) {
   170→  Formatter::HttpFormatterContext context{&headers};
   171→  config_->mutations().mutateRequestHeaders(headers, context, decoder_callbacks_->streamInfo());
   172→
   173→  maybeInitializeRouteConfigs(decoder_callbacks_);
   174→
   175→  for (const PerRouteHeaderMutation& route_config : route_configs_) {
   176→    route_config.mutations().mutateRequestHeaders(headers, context,
   177→                                                  decoder_callbacks_->streamInfo());
   178→  }
   179→
   180→  return Http::FilterHeadersStatus::Continue;
   181→}
